const sd = $getWorkflowStaticData('global');
if (!sd.seenIds) sd.seenIds = {};

const now = Date.now();
for (const [id, ts] of Object.entries(sd.seenIds)) {
  if (now - ts > 300000) delete sd.seenIds[id];
}

const raw = $json.body || $json;

let msgId;
if (raw.whatsappInboundMessage) {
  msgId = raw.whatsappInboundMessage.id || raw.whatsappInboundMessage.wamid;
} else {
  msgId = raw.message_id;
}

if (msgId && sd.seenIds[msgId]) {
  return [];
}
if (msgId) sd.seenIds[msgId] = now;

if (raw.type && raw.type.startsWith('whatsapp.inbound_message') && raw.whatsappInboundMessage) {
  const msg = raw.whatsappInboundMessage;
  return [{
    json: {
      body: {
        message_id: msg.id || msg.wamid || '',
        created_at: msg.sendTime || raw.createTime || '',
        from_phone: (msg.from || '').replace('+', ''),
        sender_name: (msg.customerProfile && msg.customerProfile.name) || '',
        to_phone: (msg.to || '').replace('+', ''),
        message: (msg.text && msg.text.body) || (msg.button && msg.button.text) || '',
        media_type: msg.type || 'text',
        status: 'received',
        event: 'message',
        quoted_message: (msg.context && msg.context.id) || null
      }
    }
  }];
}

return [$input.first()];

parameters.query:
SELECT (
  (
    SELECT message_id
    FROM inbound_message_queue
    WHERE from_phone = '{{ ($('Normalize YCloud').first().json.body.from_phone || '').replace(/'/g, "''") }}'
    ORDER BY created_at DESC, id DESC
    LIMIT 1
  ) = '{{ ($('Normalize YCloud').first().json.body.message_id || '').replace(/'/g, "''") }}'
) AS is_latest;

