const inbound = $('Normalize YCloud').first().json.body || {};
const row = $input.first().json || {};

return [{
  json: {
    body: {
      message_id: inbound.message_id,
      created_at: inbound.created_at,
      from_phone: row.from_phone || inbound.from_phone,
      to_phone: row.to_phone || inbound.to_phone,
      message: row.combined_message || inbound.message || '',
      media_type: inbound.media_type || 'text',
      status: inbound.status || 'received',
      webhook_id: inbound.webhook_id,
      event: inbound.event || 'message',
      quoted_message: inbound.quoted_message ?? null
    }
  }
}];

const raw = $input.first().json.output || '';

const DEFAULTS = {
  message: '',
  needs_human: false,
  internal_notes: '',
  should_book: false,
  should_reschedule: false,
  should_cancel: false,
  preferred_site: '',
  preferred_site_id: '',
  preferred_date: '',
  preferred_time: '',
  customer_name: '',
  customer_phone: '',
  vehicle_registration: '',
  service_type: 'katsastus',
  notes: ''
};

let parsed;
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { message: typeof raw === 'string' ? raw : String(raw) };
}

const output = { ...DEFAULTS, ...parsed };
if (typeof output.message !== 'string') {
  output.message = String(output.message || '');
}

const siteMap = {
  'vaajakoski': '58', 'jämsä': '59', 'jamsa': '59',
  'laukaa': '60', 'leppävesi': '60', 'muurame': '61'
};
if (!output.preferred_site_id && output.preferred_site) {
  const key = output.preferred_site.toLowerCase();
  for (const [name, id] of Object.entries(siteMap)) {
    if (key.includes(name)) { output.preferred_site_id = id; break; }
  }
}

return [{ json: { output } }];

const item = $input.first();
const output = item.json.output || {};
let message = String(output.message || '');

message = message
  .replace(/[—–]/g, ' - ')
  .replace(/\s{2,}/g, ' ')
  .trim();

return [{ json: { ...item.json, output: { ...output, message } } }];

