={{
(() => {
  const o = $json.output || {};
  const name = (o.customer_name || '').trim();
  const parts = name ? name.split(' ').filter(Boolean) : [];
  const firstName = parts[0] || '';
  const lastName = parts.slice(1).join(' ') || firstName;

  const phone = o.customer_phone || $('Normalize YCloud').first().json.body.from_phone || '';

  const timeMap = {
    'aamu': '09:00',
    'aamupäivä': '10:00',
    'päivä': '12:00',
    'iltapäivä': '14:00',
    'ilta': '16:00',
  };

  let timeStr = (o.preferred_time || '09:00').toString().trim().replace('.', ':');
  const lower = timeStr.toLowerCase();
  for (const k of Object.keys(timeMap)) {
    if (lower.includes(k)) {
      timeStr = timeMap[k];
      break;
    }
  }
  if (!timeStr.includes(':')) timeStr = '09:00';

  const slotStart = `${o.preferred_date}T${timeStr}:00+03:00`;

  return {
    registrationNumber: o.vehicle_registration || '',
    customerFirstName: firstName,
    customerLastName: lastName,
    customerPhone: phone,
    slotStart,
  };
})()
}}
